+/**
+ * Webhook notification adapter.
+ *
+ * Implements NotificationAdapter for the 'webhook' channel.
+ * Formats the notification payload as JSON and POSTs it to a URL.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type {
+  NotificationPayload,
+  NotificationResult,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+export interface WebhookConfig {
+  /** Default timeout in milliseconds for webhook requests */
+  timeoutMs: number;
+  /** Optional default headers to include in all webhook requests */
+  headers: Record<string, string>;
+}
+
+export const defaultWebhookConfig: WebhookConfig = {
+  timeoutMs: 5000,
+  headers: {},
+};
+
+/**
+ * The JSON payload sent to the webhook URL.
+ */
+export interface WebhookPayloadBody {
+  type: string;
+  recipient: string;
+  subject: string;
+  body: string;
+  metadata?: Record<string, unknown>;
+  timestamp: string;
+}
+
+/**
+ * Transport interface for sending webhook requests.
+ * Allows injecting a mock transport for testing.
+ */
+export interface WebhookTransport {
+  post(
+    url: string,
+    body: WebhookPayloadBody,
+    headers: Record<string, string>,
+    timeoutMs: number,
+  ): Promise<{ ok: boolean; status: number; error?: string }>;
+}
+
+/**
+ * Default transport that simulates successful delivery (for use until
+ * a real HTTP client is integrated). Mirrors DefaultEmailTransport pattern.
+ */
+export class DefaultWebhookTransport implements WebhookTransport {
+  private sentRequests: Array<{
+    url: string;
+    body: WebhookPayloadBody;
+    headers: Record<string, string>;
+  }> = [];
+
+  async post(
+    url: string,
+    body: WebhookPayloadBody,
+    headers: Record<string, string>,
+    _timeoutMs: number,
+  ): Promise<{ ok: boolean; status: number; error?: string }> {
+    this.sentRequests.push({ url, body, headers });
+    return { ok: true, status: 200 };
+  }
+
+  getSentRequests(): Array<{
+    url: string;
+    body: WebhookPayloadBody;
+    headers: Record<string, string>;
+  }> {
+    return [...this.sentRequests];
+  }
+}
+
+const URL_REGEX = /^https?:\/\/.+/;
+
+/**
+ * Validates that a string is an HTTP or HTTPS URL.
+ */
+export function isValidWebhookUrl(url: string): boolean {
+  return URL_REGEX.test(url);
+}
+
+/**
+ * Resolves the webhook URL from the payload.
+ * The URL can be provided as the recipient or via metadata.webhookUrl.
+ */
+export function resolveWebhookUrl(payload: NotificationPayload): string | null {
+  const metadataUrl = payload.metadata?.['webhookUrl'] as string | undefined;
+  if (metadataUrl && isValidWebhookUrl(metadataUrl)) {
+    return metadataUrl;
+  }
+  if (isValidWebhookUrl(payload.recipient)) {
+    return payload.recipient;
+  }
+  return null;
+}
+
+/**
+ * Formats a notification payload into the JSON body sent to the webhook.
+ */
+export function formatWebhookBody(payload: NotificationPayload): WebhookPayloadBody {
+  return {
+    type: payload.type,
+    recipient: payload.recipient,
+    subject: payload.subject,
+    body: payload.body,
+    metadata: payload.metadata,
+    timestamp: new Date().toISOString(),
+  };
+}
+
+export class WebhookAdapter implements NotificationAdapter {
+  readonly channel = 'webhook' as const;
+  private logger = new Logger('WebhookAdapter');
+  private config: WebhookConfig;
+  private transport: WebhookTransport;
+
+  constructor(config?: Partial<WebhookConfig>, transport?: WebhookTransport) {
+    this.config = { ...defaultWebhookConfig, ...config };
+    this.transport = transport ?? new DefaultWebhookTransport();
+  }
+
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    const url = resolveWebhookUrl(payload);
+
+    if (!url) {
+      const msg = `Invalid webhook URL: "${payload.recipient}"`;
+      this.logger.warn(msg);
+      return { success: false, error: msg };
+    }
+
+    const body = formatWebhookBody(payload);
+
+    try {
+      const result = await this.transport.post(
+        url,
+        body,
+        { 'Content-Type': 'application/json', ...this.config.headers },
+        this.config.timeoutMs,
+      );
+
+      if (result.ok) {
+        this.logger.info(`Webhook delivered to ${url}: "${payload.subject}"`);
+        return { success: true };
+      }
+
+      const errorMsg = result.error ?? `Webhook returned status ${result.status}`;
+      this.logger.warn(`Webhook delivery failed for ${url}: ${errorMsg}`);
+      return { success: false, error: errorMsg };
+    } catch (err) {
+      const errorMsg = err instanceof Error ? err.message : 'Unknown transport error';
+      this.logger.error(`Webhook transport error for ${url}: ${errorMsg}`);
+      return { success: false, error: errorMsg };
+    }
+  }
+}

